const issues = $input.first().json.data.issues.nodes;
const feedback = issues.flatMap(issue =>
  issue.comments.nodes
    .filter(c => c.body.toLowerCase().includes('feedback:') || c.body.toLowerCase().includes('learned:'))
    .map(c => ({ issueId: issue.id, title: issue.title, comment: c.body }))
);
return feedback.map(f => ({ json: f }));

const responseText = $input.first().json.content[0].text;
let updates;
try {
  updates = JSON.parse(responseText);
} catch (e) {
  throw new Error('Claude learning output is not valid JSON: ' + responseText.slice(0, 200));
}

let memory = $('Read Agent Memory').first().json.content || '';

if (updates.new_rules && updates.new_rules.length) {
  const rules = updates.new_rules.map(r => '- ' + r).join('\n');
  memory = memory.replace(/## Standing rules\n/, '## Standing rules\n' + rules + '\n');
}

if (updates.new_patterns && updates.new_patterns.length) {
  const patterns = updates.new_patterns.map(p => '- ' + p).join('\n');
  memory = memory.replace(/## Learned patterns\n/, '## Learned patterns\n' + patterns + '\n');
}

return [{ json: { content: memory } }];
